from ui_kit import page

_WEEK_RE = re.compile(r"^\d{4}-W\d{2}$")


def _error_page(message: str) -> str:
    return page("Timesheet", f'<div class="ts-error">{html.escape(message)}</div>')


def _badge(status: str) -> str:
    safe = html.escape(status)
    return f'<span class="ts-badge ts-badge--{safe}">{safe}</span>'


def _actions_cell(entry_id: int, status: str) -> str:
    if status == "draft":
        return (
            '<td class="ts-actions">'
            f'<form method="post" action="/entries/{entry_id}/submit">'
            '<button type="submit" class="ts-button">Submit</button>'
            "</form>"
            "</td>"
        )
    if status == "submitted":
        return (
            '<td class="ts-actions">'
            f'<form method="post" action="/entries/{entry_id}/approve">'
            '<button type="submit" class="ts-button">Approve</button>'
            "</form>"
            f'<form method="post" action="/entries/{entry_id}/reject">'
            '<button type="submit" class="ts-button ts-button--danger">Reject</button>'
            "</form>"
            "</td>"
        )
    return '<td class="ts-actions"></td>'


def _entry_row(entry: dict) -> str:
    project = html.escape(str(entry["project"]))
    entry_date = html.escape(str(entry["date"]))
    status = str(entry["status"])
    hours = float(entry["hours"])
    return (
        '<tr data-testid="entry-row">'
        f"<td>{entry['id']}</td>"
        f"<td>{project}</td>"
        f"<td>{entry_date}</td>"
        f"<td>{hours:.1f}</td>"
        f"<td>{_badge(status)}</td>"
        f"{_actions_cell(entry['id'], status)}"
        "</tr>"
    )


def _filter_form(week: str, project: str) -> str:
    week_value = html.escape(week)
    project_value = html.escape(project)
    return (
        '<form method="get" action="/" class="ts-toolbar" data-testid="filter-form">'
        '<input class="ts-input" type="text" name="week" '
        f'value="{week_value}" placeholder="YYYY-Www">'
        '<input class="ts-input" type="text" name="project" '
        f'value="{project_value}" placeholder="Project">'
        '<button type="submit" class="ts-button ts-button--ghost">Filter</button>'
        "</form>"
    )


def _add_form() -> str:
    return (
        '<div class="ts-card">'
        '<form method="post" action="/entries" class="ts-form" data-testid="add-form">'
        '<input class="ts-input" type="text" name="project" placeholder="Project" required>'
        '<input class="ts-input" type="text" name="date" placeholder="YYYY-MM-DD" required>'
        '<input class="ts-input" type="text" name="hours" placeholder="Hours" required>'
        '<button type="submit" class="ts-button">Add entry</button>'
        "</form>"
        "</div>"
    )


def _entries_section(entries: list[dict]) -> str:
    if not entries:
        return '<div class="ts-empty">No entries yet.</div>'
    total = sum(float(e["hours"]) for e in entries)
    rows = "".join(_entry_row(e) for e in entries)
    table = (
        '<table class="ts-table">'
        "<thead><tr>"
        "<th>ID</th><th>Project</th><th>Date</th><th>Hours</th><th>Status</th><th>Actions</th>"
        "</tr></thead>"
        f"<tbody>{rows}</tbody>"
        "</table>"
    )
    total_el = f'<div class="ts-total">Total hours: {total:.1f}</div>'
    return f'<div class="ts-card">{table}{total_el}</div>'


def _entries_body(entries: list[dict], week: str, project: str) -> str:
    return _filter_form(week, project) + _entries_section(entries) + _add_form()


def create_web_app(store_path) -> FastAPI:
    """Build the timesheet web app, backed by a single store file."""
    app = FastAPI()
    store = TimeStore(store_path)

    @app.get("/", response_class=HTMLResponse)
    def get_entries(
        week: str | None = Query(default=None),
        project: str | None = Query(default=None),
    ):
        week_value = week or ""
        project_value = project or ""

        if week_value:
            if not _WEEK_RE.match(week_value):
                return HTMLResponse(
                    _error_page(f"Invalid week label: {week_value}"), status_code=422
